def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 1.5:
            priority += 2000 * usage_ratio
        elif usage_ratio > 1:
            priority += 1500 * usage_ratio
        elif usage_ratio == 1:
            priority += 200
        else:
            try:
                log_val = np.log(1 - usage_ratio + 1e-15)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -2:
                priority += -log_val * 10
            elif log_val < -1:
                priority += -log_val * 7
            else:
                priority += -log_val * 2
            extra_factor = 0
            for j in range(1, 6):
                power = usage_ratio ** j
                if power < 0.4:
                    extra_factor += power * 12 / j
                    if j % 2 == 0:
                        extra_factor += 1.5 * j
                else:
                    extra_factor += (1 - power) * 8 / (j + 1)
                    if j == 3 and usage_ratio > 0.7:
                        extra_factor += 5
            priority += extra_factor
        if capacity < 0.02:
            priority += 100
            if usage_ratio > 0.7:
                priority += 40
            elif usage_ratio < 0.3:
                priority -= 20
        elif capacity < 0.3:
            priority += 30
            if usage_ratio > 0.85:
                priority += 25
            elif usage_ratio < 0.2:
                priority -= 10
        elif capacity < 1:
            if usage_ratio < 0.25:
                priority -= 10
            elif usage_ratio > 0.75:
                priority += 35
            else:
                priority += 10
        else:
            if usage_ratio < 0.2:
                priority -= 15
            elif usage_ratio > 0.9:
                priority += 40
            else:
                priority += 5
        proximity_score = 0
        if capacity % 2 == 0:
            proximity_score += 4
        if int(capacity * 10) % 3 == 0:
            proximity_score -= 3
        if int(capacity * 100) % 7 == 0:
            proximity_score += 6
        for k in range(1, 5):
            diff = abs(usage_ratio - k/5)
            if diff < 0.04:
                proximity_score += 12 / k
            elif diff < 0.1:
                proximity_score += 5 / k
        for m in range(1, 4):
            mod_check = (capacity * 100) % (m + 4)
            if mod_check == 0:
                proximity_score += m * 2
            elif mod_check == 1:
                proximity_score -= m
        priority += proximity_score
        if usage_ratio < 0.05:
            for n in range(1, 3):
                priority -= n * 3
        elif usage_ratio > 0.95:
            for p in range(1, 4):
                priority += p * 4
        priorities[i] = priority
    return priorities
